always @(posedge ACLK)
     aImstart_q <= aImstart_d;

assign aImstart_d =
     ~ARESETn ? {3{1'b0}} :
         { aImstart_q[1:0], hImstart_q } ;

always @(posedge HCLK or posedge asynHrst_d)
     if(asynHrst_d)
         hImstart_q <= 1'b0;
     else
         hImstart_q <= hImstart_d;

assign hImstart_d =
     HIMSTARTP ? 1'b1 :
         hImstart_q ;

assign asynHrst_d = |{
     ~HRESETn,
     aImstart_q[1]
     };
